1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2024-2026 by Oliver Bruendler
3	-- Authors: Oliver Bruendler
4	---------------------------------------------------------------------------------------------------
5	
6	---------------------------------------------------------------------------------------------------
7	-- Description
8	---------------------------------------------------------------------------------------------------
9	--- This is a synchronous packet FIFO. In contrast to a normal FIFO, it allows
10	--- dropping and repeating packets as well as detecting how many packets
11	--- there are in the FIFO.
12	--- The FIFO works in store-and-forward mode.
13	--- The FIFO assumes that all packets fit into the FIFO. Cut-through operation
14	--- as required to handle packets bigger than the FIFO is not iplemented.
15	--
16	-- Documentation:
17	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_fifo_packet.md
18	--
19	-- Note: The link points to the documentation of the latest release. If you
20	--       use an older version, the documentation might not match the code.
21	
22	---------------------------------------------------------------------------------------------------
23	-- Libraries
24	---------------------------------------------------------------------------------------------------
25	library ieee;
26	    use ieee.std_logic_1164.all;
27	    use ieee.numeric_std.all;
28	
29	library work;
30	    use work.olo_base_pkg_math.all;
31	    use work.olo_base_pkg_logic.all;
32	    use work.olo_base_pkg_string.all;
33	
34	---------------------------------------------------------------------------------------------------
35	-- Entity
36	---------------------------------------------------------------------------------------------------
37	entity olo_base_fifo_packet is
38	    generic (
39	        Width_g             : positive;
40	        Depth_g             : positive;
41	        MaxPacketSize_g     : integer                           := -1;
42	        FeatureSet_g        : string                            := "FULL";
43	        Optimization_g      : string                            := "SPEED";
44	        RamStyle_g          : string                            := "auto";
45	        RamBehavior_g       : string                            := "RBW";
46	        SmallRamStyle_g     : string                            := "auto";
47	        SmallRamBehavior_g  : string                            := "same";
48	        MaxPackets_g        : positive range 2 to positive'high := 17
49	    );
50	    port (
51	        -- Control Ports
52	        Clk           : in    std_logic;
53	        Rst           : in    std_logic;
54	        -- Input Data
55	        In_Valid      : in    std_logic := '1';
56	        In_Ready      : out   std_logic;
57	        In_Data       : in    std_logic_vector(Width_g - 1 downto 0);
58	        In_Last       : in    std_logic := '1';
59	        In_Drop       : in    std_logic := '0';
60	        In_IsDropped  : out   std_logic;
61	        -- Output Data
62	        Out_Valid     : out   std_logic;
63	        Out_Ready     : in    std_logic := '1';
64	        Out_Data      : out   std_logic_vector(Width_g - 1 downto 0);
65	        Out_Size      : out   std_logic_vector(log2ceil(Depth_g + 1) - 1 downto 0);
66	        Out_Last      : out   std_logic;
67	        Out_Next      : in    std_logic := '0';
68	        Out_Repeat    : in    std_logic := '0';
69	        -- Status
70	        PacketLevel   : out   std_logic_vector(log2ceil(MaxPackets_g + 1) - 1 downto 0);
71	        FreeWords     : out   std_logic_vector(log2ceil(Depth_g + 1) - 1 downto 0)
72	    );
73	end entity;
74	
75	---------------------------------------------------------------------------------------------------
76	-- Architecture
77	---------------------------------------------------------------------------------------------------
78	architecture rtl of olo_base_fifo_packet is
79	
80	    -- Constants
81	    constant EntityName_c       : string  := "olo_base_fifo_packet";
82	    constant SmallRamStyle_c    : string  := choose(compareNoCase(SmallRamStyle_g, "same"), RamStyle_g, SmallRamStyle_g);
83	    constant SmallRamBehavior_c : string  := choose(compareNoCase(SmallRamBehavior_g, "same"), RamBehavior_g, SmallRamBehavior_g);
84	    constant MaxPktSize_c       : natural := choose(MaxPacketSize_g = -1, Depth_g, work.olo_base_pkg_math.min(MaxPacketSize_g, Depth_g));
85	    -- Throughput optimization is not possible for FULL feature set
86	    constant ThroughputOpt_c    : boolean := compareNoCase(Optimization_g, "THROUGHPUT") and not compareNoCase(FeatureSet_g, "full");
87	
88	    -- Range definitions
89	    subtype Addr_c is integer range log2ceil(Depth_g) downto 0; -- one additional bit to differentiate between full/empty
90	    subtype AddrApp_c is integer range log2ceil(Depth_g) - 1 downto 0; -- one additional bit to differentiate between full/empty
91	
92	    -- Types
93	    type RdFsm_t is (Fetch_s, Data_s, Last_s);
94	
95	    type TwoProcess_r is record
96	        -- Write Side
97	        WrAddr         : unsigned(Addr_c); -- Shifted by Depth_g to Read pointer
98	        WrPacketStart  : unsigned(Addr_c); -- Shifted by Depth_g to Read pointer
99	        WrSize         : unsigned(Addr_c);
100	        WrPacketActive : std_logic;
101	        DropLatch      : std_logic;
102	        Full           : std_logic;
103	        -- Read Side
104	        RdAddr         : unsigned(Addr_c);
105	        RdPacketStart  : unsigned(Addr_c);
106	        RdPacketEnd    : unsigned(Addr_c);
107	        RdValid        : std_logic;
108	        RdFsm          : RdFsm_t;
109	        RdRepeat       : std_logic;
110	        RdSize         : unsigned(log2ceil(Depth_g + 1) - 1 downto 0);
111	        NextLatch      : std_logic;
112	        -- Status
113	        PacketLevel    : unsigned(log2ceil(MaxPackets_g + 1)-1 downto 0);
114	    end record;
115	
116	    -- Write address have the MSB (unused for RAM addressing) inverted. This leads to ReadAddr = WriteAddr indicating
117	    -- .. the full condition (and not the empty condition).
118	
119	    signal r, r_next : TwoProcess_r;
120	
121	    -- Instantiation signals
122	    signal RamRdAddr        : std_logic_vector(Addr_c);
123	    signal FifoInReady      : std_logic;
124	    signal RdPacketEnd      : std_logic_vector(Addr_c);
125	    signal RdPacketEndValid : std_logic;
126	    signal RamWrEna         : std_logic;
127	    signal FifoInValid      : std_logic;
128	    signal FifoOutRdy       : std_logic;
129	    signal WrAddrStdlv      : std_logic_vector(Addr_c);
130	    signal OutLastDropOnly  : std_logic;
131	
132	begin
133	
134	    -----------------------------------------------------------------------------------------------
135	    -- Assertions
136	    -----------------------------------------------------------------------------------------------
137	    assert log2(Depth_g) = log2ceil(Depth_g)
138	        report errorMessage(EntityName_c, "only power of two Depth_g is allowed")
139	        severity error;
140	
141	    assert compareNoCase(FeatureSet_g, "full") or compareNoCase(FeatureSet_g, "drop_only") or compareNoCase(FeatureSet_g, "drop_skip_only")
142	        report errorMessage(EntityName_c, "FeatureSet_g must be FULL, DROP_SKIP_ONLY or DROP_ONLY")
143	        severity error;
144	
145	    assert compareNoCase(Optimization_g, "throughput") or compareNoCase(Optimization_g, "speed")
146	        report errorMessage(EntityName_c, "Optimization_g must be THROUGHPUT or SPEED")
147	        severity error;
148	
149	    assert MaxPacketSize_g = -1 or (MaxPacketSize_g >= 1 and MaxPacketSize_g <= Depth_g)
150	        report errorMessage(EntityName_c, "MaxPacketSize_g must be -1 (auto) or in range 1 to Depth_g")
151	        severity error;
152	
153	    assert not compareNoCase(Optimization_g, "THROUGHPUT") or not compareNoCase(FeatureSet_g, "full")
154	        report errorMessage(EntityName_c, "Optimization_g = THROUGHPUT and FeatureSet_g = full are not compatible")
155	        severity error;
156	
157	    -- MaxPackets_g is only relevant for FULL/DROP_SKIP_ONLY feature set with THROUGHPUT optimization
158	
159	    -----------------------------------------------------------------------------------------------
160	    -- Combinatorial Process
161	    -----------------------------------------------------------------------------------------------
162	    p_comb : process (all) is
163	        variable v           : TwoProcess_r;
164	        variable In_Ready_v  : std_logic;
165	        variable InDrop_v    : std_logic;
166	        variable OutLast_v   : std_logic;
167	        variable OutNext_v   : std_logic;
168	        variable OutRepeat_v : std_logic;
169	    begin
170	        -- hold variables stable
171	        v := r;
172	
173	        -- *** Write side ***
174	
175	        -- Default Values
176	        In_Ready_v  := ((not r.Full) and FifoInReady) or r.DropLatch;
177	        InDrop_v    := r.DropLatch;
178	        RamWrEna    <= '0';
179	        FifoInValid <= '0';
180	
181	        -- Implement getting free after Full
182	        if r.WrAddr /= r.RdPacketStart then
183	            v.Full := '0';
184	        end if;
185	
186	        -- Handle packet drop between samples
187	        if In_Drop = '1' and (r.WrPacketActive = '1' or In_Valid = '1') then
188	            v.DropLatch := '1';
189	        end if;
190	
191	        if In_Valid = '1' and In_Ready_v = '1' then
192	            -- Packet Active
193	            v.WrPacketActive := '1';
194	
195	            -- Handle FIFO becomes Full
196	            if r.WrAddr = r.RdPacketStart-1 then
197	                v.Full := '1';
198	            end if;
199	
200	            -- Increment Address
201	            if r.WrAddr = Depth_g*2 - 1 then
202	                v.WrAddr := (others => '0');
203	            else
204	                v.WrAddr := r.WrAddr + 1;
205	            end if;
206	
207	            -- Handle packet drop on sample
208	            if In_Drop = '1' then
209	                InDrop_v    := '1';
210	                v.DropLatch := '1';
211	            end if;
212	
213	            -- Detect packets larger than allowed
214	            if r.WrSize = MaxPktSize_c then
215	                v.DropLatch := '1';
216	            else
217	                v.WrSize := r.WrSize + 1;
218	            end if;
219	
220	            -- Handle end of packet
221	            if In_Last = '1' then
222	                -- Packet dropped
223	                if InDrop_v = '1' then
224	                    v.WrAddr := r.WrPacketStart;
225	                -- Packet stored
226	                else
227	                    v.WrPacketStart := r.WrAddr + 1;
228	                    FifoInValid     <= '1';
229	                end if;
230	                -- Reset signals for all packet ends
231	                v.DropLatch      := '0';
232	                v.WrSize         := to_unsigned(1, r.WrSize'length);
233	                v.WrPacketActive := '0';
234	            end if;
235	
236	            -- Write to RAM
237	            RamWrEna <= '1';
238	
239	        end if;
240	
241	        -- Avoid blocking due to Full detection for oversized packets
242	        if r.DropLatch = '1' then
243	            v.WrAddr := r.WrPacketStart;
244	            v.Full   := '0';
245	        end if;
246	
247	        -- Output
248	        In_IsDropped <= InDrop_v;
249	        In_Ready     <= In_Ready_v;
250	
251	        -- *** Status ***
252	
253	        -- *** Read side ***
254	
255	        -- Default Values
256	        FifoOutRdy <= '0';
257	        OutLast_v  := '0';
258	
259	        -- Suppress deactivated feature sets
260	        OutNext_v   := '0';
261	        OutRepeat_v := '0';
262	        if compareNoCase(FeatureSet_g, "full") then
263	            OutRepeat_v := Out_Repeat;
264	        end if;
265	        if not compareNoCase(FeatureSet_g, "drop_only") then
266	            OutNext_v := Out_Next;
267	        end if;
268	
269	        -- FSM
270	        case r.RdFsm is
271	            when Fetch_s =>
272	                -- Set start address after completion of a packet
273	                v.RdPacketStart := r.RdAddr;
274	
275	                -- Repeat packet
276	                if r.RdRepeat = '1' then
277	                    if r.RdPacketEnd = r.RdPacketStart then
278	                        v.RdFsm := Last_s;
279	                    else
280	                        v.RdFsm := Data_s;
281	                    end if;
282	                    v.RdRepeat := '0';
283	                    v.RdAddr   := r.RdPacketStart;
284	                    v.RdValid  := '1';
285	                    -- Revert signals for repeated packets
286	                    v.RdPacketStart := r.RdPacketStart;
287	
288	                -- Read next packet info
289	                elsif RdPacketEndValid = '1' then
290	                    FifoOutRdy <= '1';
291	                    v.RdRepeat := '0';
292	                    if unsigned(RdPacketEnd) = r.RdAddr then
293	                        v.RdFsm := Last_s;
294	                    else
295	                        v.RdFsm := Data_s;
296	                    end if;
297	                    v.RdPacketEnd := unsigned(RdPacketEnd);
298	                    v.RdValid     := '1';
299	                    -- Packet size is not supported in drop_only mode
300	                    if not compareNoCase(FeatureSet_g, "drop_only") then
301	                        v.RdSize := unsigned(RdPacketEnd) - r.RdAddr + 1;
302	                    end if;
303	
304	                end if;
305	
306	            when Data_s =>
307	                -- Transaction
308	                if Out_Ready = '1' then
309	                    if v.RdAddr = Depth_g*2 - 1 then
310	                        v.RdAddr := (others => '0');
311	                    else
312	                        v.RdAddr := v.RdAddr + 1;
313	                    end if;
314	
315	                    -- Handle normal end of packet
316	                    if r.RdAddr = r.RdPacketEnd - 1 then
317	                        v.RdFsm := Last_s;
318	                    end if;
319	
320	                    -- Handle abortion of packet
321	                    if OutNext_v = '1' or r.NextLatch = '1' then
322	                        OutLast_v := '1';
323	                        v.RdValid := '0';
324	                        v.RdFsm   := Fetch_s;
325	                        v.RdAddr  := r.RdPacketEnd + 1;
326	                    end if;
327	
328	                end if;
329	
330	            when Last_s =>
331	                -- Assert last in this state (combinatorial)
332	                OutLast_v := '1';
333	
334	                if Out_Ready = '1' then
335	                    -- Increment Address
336	                    if v.RdAddr = Depth_g*2 - 1 then
337	                        v.RdAddr := (others => '0');
338	                    else
339	                        v.RdAddr := v.RdAddr + 1;
340	                    end if;
341	
342	                    -- Abort is not handled separately because it does not have any effect on the last word of a packet
343	
344	                    -- To to idle cycle for fetch after packet completed
345	                    v.RdValid := '0';
346	                    v.RdFsm   := Fetch_s;
347	
348	                    -- Fast-path for back-to-back packets: If the next packet is already valid, skip the idle cycle and directly go to data state
349	                    -- This is used for Optimization_g=THROUGHPUT to achieve maximum throughput for back-to-back packets at the cost of
350	                    -- slightly lower clock frequency. It is NOT supported for the FULL feature set because repeating packets is not possible in this case.
351	                    if RdPacketEndValid = '1' and ThroughputOpt_c then
352	                        v.RdPacketStart := r.RdAddr;
353	                        FifoOutRdy      <= '1';
354	                        v.RdRepeat      := '0';
355	                        if unsigned(RdPacketEnd)-1 = r.RdAddr then
356	                            v.RdFsm := Last_s;
357	                        else
358	                            v.RdFsm := Data_s;
359	                        end if;
360	                        v.RdPacketEnd := unsigned(RdPacketEnd);
361	                        v.RdValid     := '1';
362	                        -- Packet size is not supported in drop_only mode
363	                        if not compareNoCase(FeatureSet_g, "drop_only") then
364	                            v.RdSize := unsigned(RdPacketEnd) - r.RdAddr;
365	                        end if;
366	                    end if;
367	                end if;
368	
369	            -- coverage off
370	            when others => null; -- unreachable code
371	            -- coverage on
372	
373	        end case;
374	
375	        -- In throughput optimization mode, free up space in the FIFO whenever read (allowed because packets
376	        -- are never repeated in this mode).
377	        if ThroughputOpt_c then
378	            v.RdPacketStart := r.RdAddr;
379	        end if;
380	
381	        -- Output handling
382	        RamRdAddr <= std_logic_vector(v.RdAddr);
383	        Out_Valid <= r.RdValid;
384	        if compareNoCase(FeatureSet_g, "drop_only") then
385	            OutLast_v := OutLastDropOnly; -- Override default assignment further up in the process
386	            Out_Size  <= (others => 'X');
387	        else
388	            Out_Size <= std_logic_vector(r.RdSize);
389	        end if;
390	        Out_Last <= OutLast_v;
391	
392	        -- Latch Next between samples
393	        if r.RdValid = '1' and Out_Ready = '1' and OutLast_v = '1' then
394	            v.NextLatch := '0';
395	        elsif r.RdValid = '1' and OutNext_v = '1' then
396	            v.NextLatch := '1';
397	        end if;
398	
399	        -- Handle Packet Level
400	        if In_Valid = '1' and In_Ready_v = '1' and In_Last = '1' and InDrop_v = '0' then
401	            v.PacketLevel := r.PacketLevel + 1;
402	        end if;
403	        if r.RdValid = '1' and Out_Ready = '1' and OutLast_v = '1' and r.RdRepeat = '0' and OutRepeat_v = '0' then
404	            v.PacketLevel := v.PacketLevel - 1;
405	        end if;
406	        PacketLevel <= std_logic_vector(r.PacketLevel);
407	
408	        -- Handle Free Space
409	        FreeWords <= std_logic_vector(r.RdPacketStart(FreeWords'range) - r.WrAddr(FreeWords'range));
410	
411	        -- Latch Repeat between samples
412	        -- Clearing is done in FSM
413	        if OutRepeat_v = '1' and r.RdValid = '1' then
414	            v.RdRepeat := '1';
415	        end if;
416	
417	        -- Assign signal
418	        r_next <= v;
419	
420	    end process;
421	
422	    -----------------------------------------------------------------------------------------------
423	    -- Sequential Process
424	    -----------------------------------------------------------------------------------------------
425	    p_seq : process (Clk) is
426	    begin
427	        if rising_edge(Clk) then
428	            r <= r_next;
429	            if Rst = '1' then
430	                r.WrAddr         <= to_unsigned(Depth_g, r.WrAddr'length);
431	                r.WrPacketStart  <= to_unsigned(Depth_g, r.WrPacketStart'length);
432	                r.WrSize         <= to_unsigned(1, r.WrSize'length);
433	                r.WrPacketActive <= '0';
434	                r.DropLatch      <= '0';
435	                r.Full           <= '0';
436	                r.RdAddr         <= (others => '0');
437	                r.RdPacketStart  <= (others => '0');
438	                r.RdFsm          <= Fetch_s;
439	                r.RdRepeat       <= '0';
440	                r.RdValid        <= '0';
441	                r.NextLatch      <= '0';
442	                r.PacketLevel    <= (others => '0');
443	            end if;
444	        end if;
445	    end process;
446	
447	    -----------------------------------------------------------------------------------------------
448	    -- Component Instantiations
449	    -----------------------------------------------------------------------------------------------
450	
451	    -- Fix the "shift by depth" between Write/Read address pointers for full/empty detection
452	    WrAddrStdlv(AddrApp_c)        <= std_logic_vector(r.WrAddr(AddrApp_c));
453	    WrAddrStdlv(WrAddrStdlv'high) <= not r.WrAddr(r.WrAddr'high);
454	
455	    -- Main RAM
456	    b_ram : block is
457	        -- RAM stores last for drop_only feature set
458	        constant RamWidth_c : natural := choose(not compareNoCase(FeatureSet_g, "drop_only"), Width_g, Width_g+1);
459	
460	        signal RamInData  : std_logic_vector(RamWidth_c-1 downto 0);
461	        signal RamOutData : std_logic_vector(RamWidth_c-1 downto 0);
462	    begin
463	
464	        p_map : process (all) is
465	        begin
466	            if not compareNoCase(FeatureSet_g, "drop_only") then
467	                -- Input
468	                RamInData <= In_Data;
469	                -- Output
470	                Out_Data <= RamOutData;
471	            else
472	                -- Input
473	                RamInData(RamInData'high) <= In_Last;
474	                RamInData(In_Data'range)  <= In_Data;
475	                -- Output
476	                OutLastDropOnly <= RamOutData(RamOutData'high); -- assigned in main comb process
477	                Out_Data        <= RamOutData(Out_Data'range);
478	            end if;
479	        end process;
480	
481	        i_ram : entity work.olo_base_ram_sdp
482	            generic map (
483	                Depth_g         => Depth_g,
484	                Width_g         => RamWidth_c,
485	                RamStyle_g      => RamStyle_g,
486	                RamBehavior_g   => RamBehavior_g
487	            )
488	            port map (
489	                Clk     => Clk,
490	                Wr_Addr => WrAddrStdlv(AddrApp_c), -- Additional bit for full/empty differentiation is stripped
491	                Wr_Ena  => RamWrEna,
492	                Wr_Data => RamInData,
493	                Rd_Addr => RamRdAddr(AddrApp_c),   -- Additional bit for full/empty differentiation is stripped
494	                Rd_Data => RamOutData
495	            );
496	
497	    end block;
498	
499	    -- FIFO transfer packet ends for full feature set
500	    g_small_fifo : if not compareNoCase(FeatureSet_g, "drop_only") generate
501	
502	        i_pktend_fifo : entity work.olo_base_fifo_sync
503	            generic map (
504	                Width_g         => log2ceil(Depth_g)+1,
505	                -- Throughput optimization requires at least 2 packets to work
506	                Depth_g         => choose(ThroughputOpt_c and MaxPackets_g = 2, MaxPackets_g, MaxPackets_g-1),
507	                RamStyle_g      => SmallRamStyle_c,
508	                RamBehavior_g   => SmallRamBehavior_c,
509	                ReadyRstState_g => '0'
510	            )
511	            port map (
512	                Clk           => Clk,
513	                Rst           => Rst,
514	                In_Data       => WrAddrStdlv,
515	                In_Valid      => FifoInValid,
516	                In_Ready      => FifoInReady,
517	                Out_Data      => RdPacketEnd,
518	                Out_Valid     => RdPacketEndValid,
519	                Out_Ready     => FifoOutRdy
520	            );
521	
522	    end generate;
523	
524	    -- For drop_only feature set only the last end address must be latched
525	    g_no_small_fifo : if compareNoCase(FeatureSet_g, "drop_only") generate
526	
527	        FifoInReady <= '1';
528	
529	        p_latch : process (Clk) is
530	        begin
531	            if rising_edge(Clk) then
532	
533	                -- Read
534	                if FifoOutRdy = '1' then
535	                    RdPacketEndValid <= '0';
536	                end if;
537	
538	                -- Write
539	                if FifoInValid = '1' then
540	                    RdPacketEndValid <= '1';
541	                    RdPacketEnd      <= WrAddrStdlv;
542	                end if;
543	
544	                -- Reset
545	                if Rst = '1' then
546	                    RdPacketEndValid <= '0';
547	                end if;
548	            end if;
549	        end process;
550	
551	    end generate;
552	
553	end architecture;
554

