22	library olo;
23	    use olo.olo_base_pkg_math.all;
24	    use olo.olo_base_pkg_logic.all;
25	
26	---------------------------------------------------------------------------------------------------
27	-- Entity
28	---------------------------------------------------------------------------------------------------
29	-- vunit: run_all_in_same_sim
30	entity olo_base_fifo_packet_tb is
31	    generic (
32	        RandomStall_g   : boolean := false;
33	        RandomPackets_g : integer := 100;
34	        FeatureSet_g    : string  := "FULL";
35	        Optimization_g  : string  := "THROUGHPUT";
36	        UsePacketSize_g : boolean := true;
37	        runner_cfg      : string
38	    );
39	end entity;
40	
41	architecture sim of olo_base_fifo_packet_tb is
42	
43	    -----------------------------------------------------------------------------------------------
44	    -- Constants
45	    -----------------------------------------------------------------------------------------------
46	    constant Width_c         : integer := 16;
47	    constant Depth_c         : integer := 32;
48	    constant MaxPackets_c    : integer := 4;
49	    constant MaxPacketSize_c : integer := choose(UsePacketSize_g, Depth_c / 2, Depth_c);
50	
51	    -----------------------------------------------------------------------------------------------
52	    -- TB Defnitions
53	    -----------------------------------------------------------------------------------------------
54	    constant ClockFrequency_c : real := 100.0e6;
55	    constant ClockPeriod_c    : time := (1 sec) / ClockFrequency_c;
56	    constant CaseDelay_c      : time := ClockPeriod_c*20;
57	    shared variable Random_v  : RandomPType;
58	
59	    shared variable InDelay_v  : time := 0 ns;
60	    shared variable OutDelay_v : time := 0 ns;
61	
62	    -- *** Verification Compnents ***
63	    constant AxisMaster_c           : axi_stream_master_t := new_axi_stream_master (
64	        data_length => Width_c,
65	        user_length => 1,
66	        stall_config => new_stall_config(choose(RandomStall_g, 0.5, 0.0), 0, 10)
67	    );
68	    constant AxisSlave_c            : axi_stream_slave_t  := new_axi_stream_slave (
69	        data_length => Width_c,
70	        user_length => log2ceil(Depth_c+1),
71	        stall_config => new_stall_config(choose(RandomStall_g, 0.5, 0.0), 0, 10)
72	    );
73	    constant AxisNextRepeatMaster_c : axi_stream_master_t := new_axi_stream_master (
74	        data_length => 2,
75	        stall_config => new_stall_config(0.0, 0, 0)
76	    );
77	    constant AxisIsDropedSlave_c    : axi_stream_slave_t  := new_axi_stream_slave (
78	        data_length => 1,
79	        stall_config => new_stall_config(0.0, 0, 0)
80	    );
81	
82	    procedure pushPacket (
83	        signal  net : inout network_t;
84	        size        : integer;
85	        startVal    : integer := 1;
86	        dropAt      : integer := integer'high;
87	        isDroppedAt : integer := integer'high;
88	        blocking    : boolean := false) is
89	        variable Tlast_v     : std_logic := '0';
90	        variable Drop_v      : std_logic := '0';
91	        variable IsDropped_v : std_logic_vector(0 downto 0);
92	        variable Tuser_v     : std_logic_vector(0 downto 0);
93	    begin
94	
95	        -- Loop over data-beats
96	        for i in 0 to size-1 loop
97	            -- Expect isdropped
98	            if isDroppedAt <= i or dropAt <= i then
99	                IsDropped_v := "1";
100	            else
101	                IsDropped_v := "0";
102	            end if;
103	            check_axi_stream(net, AxisIsDropedSlave_c, IsDropped_v, blocking => false, msg => "IsDropped_v");
104	
105	            -- Push Data
106	            if i = size-1 then
107	                Tlast_v := '1';
108	            end if;
109	            if dropAt = i then
110	                Drop_v := '1';
111	            else
112	                Drop_v := '0';
113	            end if;
114	            Tuser_v(0) := Drop_v;
115	            if InDelay_v > 0 ns then
116	                wait for InDelay_v;
117	            end if;
118	            push_axi_stream(net, AxisMaster_c, toUslv(startVal + i, Width_c), tlast => Tlast_v, tuser => Tuser_v);
119	        end loop;
120	
121	        if blocking then
122	            wait_until_idle(net, as_sync(AxisMaster_c));
123	        end if;
124	    end procedure;
125	
126	    procedure checkPacket (
127	        signal  net : inout network_t;
128	        size        : integer;
129	        startVal    : integer := 1;
130	        nextAt      : integer := -1;
131	        repeatAt    : integer := -1;
132	        pktSize     : integer := -1; -- if not specified "size" is used
133	        blocking    : boolean := false) is
134	        variable Tlast_v          : std_logic := '0';
135	        variable Next_v, Repeat_v : std_logic := '0';
136	        variable Size_v           : std_logic_vector(log2ceil(Depth_c+1) - 1 downto 0);
137	    begin
138	
139	        -- Loop over data-beats
140	        for i in 0 to size-1 loop
141	            -- Next/Repeat
142	            Next_v   := '0';
143	            Repeat_v := '0';
144	            if nextAt = i then
145	                Next_v := '1';
146	            end if;
147	            if repeatAt = i then
148	                Repeat_v := '1';
149	            end if;
150	            if FeatureSet_g /= "DROP_ONLY" then
151	                push_axi_stream(net, AxisNextRepeatMaster_c, Repeat_v & Next_v);
152	            end if;
153	            -- Data
154	            if i = size-1 then
155	                Tlast_v := '1';
156	            end if;
157	            if OutDelay_v > 0 ns then
158	                wait for OutDelay_v;
159	            end if;
160	            -- for FULL check size
161	            if FeatureSet_g /= "DROP_ONLY" then
162	                if pktsize = -1 then
163	                    Size_v := toUslv(size, Size_v'length);
164	                else
165	                    Size_v := toUslv(pktSize, Size_v'length);
166	                end if;
167	            -- ... else the size is not present
168	            else
169	                Size_v := (others => '0');
170	            end if;
171	            check_axi_stream(net, AxisSlave_c, toUslv(startVal + i, Width_c), tlast => Tlast_v, tuser => Size_v, blocking => false);
172	        end loop;
173	
174	        if blocking then
175	            wait_until_idle(net, as_sync(AxisSlave_c));
176	        end if;
177	    end procedure;
