780	                            -- Skip 10% of the packets prematurely
781	                            ReadSize_v := PacketSize_v;
782	                            if Random_v.RandInt(0, 99) < 10 then
783	                                NextAt_v   := Random_v.RandInt(0, PacketSize_v-1);
784	                                ReadSize_v := NextAt_v+1;
785	                            else
786	                                NextAt_v := PacketSize_v+1; -- Don't skip
787	                            end if;
788	                            -- Random Repetition position
789	                            if i < Repetitions_v then
790	                                RepeatAt_v := Random_v.RandInt(0, minimum(ReadSize_v-1, NextAt_v));
791	                            else
792	                                RepeatAt_v := PacketSize_v+1; -- Don't repeat
793	                            end if;
794	                            checkPacket(net, ReadSize_v, 16#100#*pkt, repeatAt => RepeatAt_v, nextAt => NextAt_v, pktSize => PacketSize_v);
795	
796	                        end loop;
797	
798	                    end if;
799	
800	                end loop;
801	
802	            end if;
803	
804	            -- End case condition
805	            wait for CaseDelay_c;
806	            -- Due to a VUNit bug wait_until_idle does not work correctly here
807	            if In_Valid = '1' then
808	                wait until In_Valid = '0';
809	            end if;
810	            wait_until_idle(net, as_sync(AxisSlave_c));
811	            wait_until_idle(net, as_sync(AxisNextRepeatMaster_c));
812	            wait_until_idle(net, as_sync(AxisIsDropedSlave_c));
813	
814	        end loop;
815	
816	        -- TB done
817	        test_runner_cleanup(runner);
818	    end process;
819	
820	    -----------------------------------------------------------------------------------------------
821	    -- Clock
822	    -----------------------------------------------------------------------------------------------
823	    Clk <= not Clk after 0.5*ClockPeriod_c;
824	
825	    -----------------------------------------------------------------------------------------------
826	    -- DUT
827	    -----------------------------------------------------------------------------------------------
828	    i_dut : entity olo.olo_base_fifo_packet
829	        generic map (
830	            Width_g             => Width_c,
831	            Depth_g             => Depth_c,
832	            FeatureSet_g        => FeatureSet_g,
833	            MaxPacketSize_g     => choose(UsePacketSize_g, MaxPacketSize_c, -1),
834	            RamStyle_g          => "auto",
835	            RamBehavior_g       => "RBW",
836	            SmallRamStyle_g     => "same",
837	            SmallRamBehavior_g  => "same",
838	            MaxPackets_g        => MaxPackets_c,
839	            Optimization_g      => Optimization_g
840	        )
841	        port map (
842	            Clk           => Clk,
843	            Rst           => Rst,
844	            In_Valid      => In_Valid,
845	            In_Ready      => In_Ready,
846	            In_Data       => In_Data,
847	            In_Last       => In_Last,
848	            In_Drop       => In_Drop,
849	            In_IsDropped  => In_IsDropped,
850	            Out_Valid     => Out_Valid,
851	            Out_Ready     => Out_Ready,
852	            Out_Data      => Out_Data,
853	            Out_Size      => Out_Size,
854	            Out_Last      => Out_Last,
855	            Out_Next      => Out_Next,
856	            Out_Repeat    => Out_Repeat,
857	            PacketLevel   => PacketLevel,
858	            FreeWords     => FreeWords
859	        );
860	
861	    -----------------------------------------------------------------------------------------------
862	    -- Verification Components
863	    -----------------------------------------------------------------------------------------------
864	    vc_stimuli : entity vunit_lib.axi_stream_master
865	        generic map (
866	            Master => AxisMaster_c
867	        )
868	        port map (
869	            Aclk     => Clk,
870	            TValid   => In_Valid,
871	            TReady   => In_Ready,
872	            TData    => In_Data,
873	            TLast    => In_Last,
874	            TUser(0) => In_Drop
875	        );
876	
877	    b_resp : block is
878	        signal OutSize : std_logic_vector(Out_Size'range);
879	    begin
880	        -- Do only check size for FULL feature set
881	        OutSize <= Out_Size when FeatureSet_g /= "DROP_ONLY" else (others => '0');
882	
883	        vc_response : entity vunit_lib.axi_stream_slave
884	            generic map (
885	                Slave => AxisSlave_c
886	            )
887	            port map (
888	                Aclk   => Clk,
889	                TValid => Out_Valid,
890	                TReady => Out_Ready,
891	                TData  => Out_Data,
892	                TLast  => Out_Last,
893	                TUser  => OutSize
894	            );
895	
896	    end block;
897	
898	    b_nr : block is
899	        signal Ready       : std_logic;
900	        signal NextLocal   : std_logic;
901	        signal RepeatLocal : std_logic;
902	    begin
903	        Ready <= Out_Ready and Out_Valid;
904	
905	        vc_next_repeat : entity vunit_lib.axi_stream_master
906	            generic map (
907	                Master => AxisNextRepeatMaster_c
908	            )
909	            port map (
910	                Aclk        => Clk,
911	                TValid      => open,
912	                TReady      => Ready,
913	                TData(0)    => NextLocal,
914	                TData(1)    => RepeatLocal
915	            );
916	
917	        -- Supporess Next/Repeat before full handshaking (tested in olo_base_fifo_packet_tb)
918	        Out_Next   <= NextLocal and Out_Ready and Out_Valid;
919	        Out_Repeat <= RepeatLocal and Out_Ready and Out_Valid;
920	    end block;
921	
922	    b_id : block is
923	        signal Valid : std_logic;
924	    begin
925	        Valid <= In_Valid and In_Ready;
926	
927	        vc_isdropped : entity vunit_lib.axi_stream_slave
928	            generic map (
929	                Slave => AxisIsDropedSlave_c
930	            )
931	            port map (
932	                Aclk      => Clk,
933	                TValid    => Valid,
934	                TData(0)  => In_IsDropped
935	            );
936	
937	    end block;
938	
939	end architecture;
